const PIDX={};
PRODS.forEach(p=>{PIDX[p.sku.toLowerCase()]=p;PIDX[p.sku.toUpperCase()]=p;});

function findProd(sku){
  if(!sku||sku==='—')return null;
  const k=String(sku).trim();
  return PIDX[k]||PIDX[k.toLowerCase()]||PIDX[k.toUpperCase()]||null;
}

function getCordon(ciudad){
  if(!ciudad)return 3;
  return ZONA[String(ciudad).toLowerCase().trim()]||3;
}

function hdr(t){return t?{'Authorization':'Bearer '+t}:{};}

function calcular(order,ship){
  const item=order.order_items?.[0]||{};
  const venta=order.total_amount||0;
  const sku=item.item?.seller_sku||item.item?.id||'';
  const prod=findProd(sku);

  // Comisión real de ML (sale_fee del ítem, o estimado 14%)
  const comision=Math.abs(item.sale_fee||venta*0.14);
  // Cuotas: diferencia entre lo pagado y el precio base
  const cuotas=(order.payments||[]).reduce((s,p)=>s+Math.max(0,Math.abs(p.total_paid_amount||0)-Math.abs(p.transaction_amount||0)),0);
  // Costo de adquisición del producto
  const costo=prod?prod.ars:0;
  // IVA implícito en el precio de venta (obligación fiscal del vendedor)
  const ivaPct=prod?prod.iva/100:0.21;
  const iva=(venta/(1+ivaPct))*ivaPct;
  // Publicidad ML (5% si la campaña está activa) — descuento adicional a la comisión
  const pub=(prod&&!prod.pub)?0:venta*0.05;
  // IIBB: ML retiene un porcentaje automáticamente (SIRTAC, provincial)
  // Pero el IIBB total que debés declarar es ~4% sobre la venta
  // Usamos 4% como aproximación del gasto real
  const iibb=venta*0.04;

  const logistic=ship?.logistic_type||order.shipping?.logistic_type||'';
  const tags=order.tags||[];
  const shipTags=ship?.tags||[];
  const ciudad=ship?.receiver_address?.city?.name||order.shipping?.receiver_address?.city?.name||'';
  const estado=ship?.receiver_address?.state?.name||'';

  const isFull=logistic==='fulfillment'||logistic==='self_service_fulfillment'
    ||logistic.includes('fulfillment')||tags.includes('fulfillment');

  // Flex: puede venir en order.tags, ship.tags, o logistic_type
  const isFlex=tags.includes('flex_delivery')
    ||shipTags.includes('flex_delivery')
    ||logistic==='me2'
    ||order.shipping?.logistic_type==='me2';

  // "no_shipping" = comprador pagó su propio envío → costoEnvio = 0 para el vendedor
  const noShipping=tags.includes('no_shipping');

  let modal='Correo',costoEnvio=0,bonifEnvio=0;

  // ship.cost viene NEGATIVO cuando ML te cobra el envío (gratis para el comprador)
  const sc=ship?.cost??order.shipping?.cost??0;

  if(isFull){
    modal='Full';costoEnvio=0;bonifEnvio=0;
  } else if(isFlex){
    modal='Flex';
    const cordon=getCordon(ciudad);
    bonifEnvio=849;
    costoEnvio=Math.max(0,(CORD[cordon]||CORD[3])-bonifEnvio);
  } else if(noShipping){
    // Comprador pagó el envío o retiro en punto → neutro para el vendedor
    modal='Correo';costoEnvio=0;bonifEnvio=0;
  } else {
    modal='Correo';
    if(sc<0){
      // ship.cost negativo = ML te cobra el envío (entregado)
      costoEnvio=Math.abs(sc);
    } else {
      // Orden no entregada aún: ship.cost = 0 hasta la entrega
      // Estimamos según free_shipping: si fue gratis para el comprador, lo pagamos nosotros
      const freeShip=ship?.free_shipping===true||order.shipping?.free_shipping===true;
      if(freeShip){
        // Estimar costo de envío gratis según destino
        // Si está en GBA → ~$5.000, interior → ~$8.000-15.000
        // Usamos 0 hasta confirmar con la entrega (después ship.cost va a ser negativo)
        costoEnvio=0; // pendiente de entrega
      } else {
        costoEnvio=0; // comprador pagó
      }
    }
    bonifEnvio=0;
  }
  // Ganancia neta = precio venta - lo que cobra ML - tu costo de producto - IVA que declarás - publicidad - envío a tu cargo
  const ganancia=venta-comision-cuotas-costo-iva-pub-iibb-costoEnvio;
  return {
    id:order.id,
    fecha:(order.date_created||'').split('T')[0],
    sku:sku||'—',desc:item.item?.title||'—',
    unidades:item.quantity||1,ciudad,estado,modal,
    cordon:isFlex?getCordon(ciudad):null,
    venta,comision:Math.round(comision),cuotas:Math.round(cuotas),
    costo:Math.round(costo),iva:Math.round(iva),ivaPct:prod?.iva||21,
    pub:Math.round(pub),iibb:Math.round(iibb),
    costoEnvio:Math.round(costoEnvio),bonifEnvio:Math.round(bonifEnvio),
    ganancia:Math.round(ganancia),
    pct:venta>0?ganancia/venta:0,
    sinProducto:!prod,
    sinZona:isFlex&&!ZONA[String(ciudad).toLowerCase().trim()],
    // Debug fields
    _raw_ship_cost:ship?.cost,
    _raw_free:order.shipping?.free_shipping,
    _raw_logistic:logistic,
    _raw_tags:tags
  };
}

