app.get('/orders/all',async(req,res)=>{
  const token=req.headers['x-ml-token'];
  if(!token)return res.status(401).json({error:'Token requerido'});
  const{seller_id,from,to}=req.query;
  try{
    let all=[],offset=0,total=null;
    while(total===null||offset<total){
      const p=new URLSearchParams({seller:seller_id,'order.date_created.from':from,'order.date_created.to':to,'order.status':'paid',offset,limit:50,sort:'date_desc'});
      const r=await fetch(ML+'/orders/search?'+p,{headers:hdr(token)});
      const data=await r.json();
      if(data.error||!data.results)break;
      all=all.concat(data.results);
      total=data.paging?.total||0;
      offset+=50;
      if(all.length>=total)break;
    }
    const processed=[];
    for(let i=0;i<all.length;i+=5){
      const batch=all.slice(i,i+5);
      const res2=await Promise.all(batch.map(async o=>{
        let ship=null;
        if(o.shipping?.id){
          try{const sr=await fetch(ML+'/shipments/'+o.shipping.id,{headers:hdr(token)});if(sr.ok)ship=await sr.json();}
          catch(e){}
        }
        return calcular(o,ship);
      }));
      processed.push(...res2);
    }
    res.json({orders:processed,total:processed.length});
  }catch(e){res.status(500).json({error:e.message});}
});

app.get('/debug/order/:id',async(req,res)=>{
  const token=req.headers['x-ml-token'];
  if(!token)return res.status(401).json({error:'Token requerido'});
  try{
    const r=await fetch(ML+'/orders/'+req.params.id,{headers:hdr(token)});
    const order=await r.json();
    let ship=null;
    if(order.shipping?.id){
      const sr=await fetch(ML+'/shipments/'+order.shipping.id,{headers:hdr(token)});
      ship=await sr.json();
    }
    const item=order.order_items?.[0]||{};
    res.json({
      id:order.id,fecha:order.date_created,
      sku:item.item?.seller_sku,titulo:item.item?.title,
      precio:item.unit_price,cantidad:item.quantity,sale_fee:item.sale_fee,
      total_amount:order.total_amount,paid_amount:order.paid_amount,
      ORDER_TAGS:order.tags,
      SHIPPING_LOGISTIC:order.shipping?.logistic_type,
      SHIPPING_COST:order.shipping?.cost,
      SHIPPING_FREE:order.shipping?.free_shipping,
      SHIP_LOGISTIC:ship?.logistic_type,
      SHIP_COST:ship?.cost,
      SHIP_TAGS:ship?.tags,
      SHIP_COST_COMPONENTS:ship?.cost_components,
      SHIP_FREE_METHODS:ship?.free_methods,
      CIUDAD:ship?.receiver_address?.city?.name,
      PROVINCIA:ship?.receiver_address?.state?.name,
      PAYMENTS:(order.payments||[]).map(p=>({pagado:p.total_paid_amount,base:p.transaction_amount,cuotas:p.installments})),
      CALCULO:calcular(order,ship)
    });
  }catch(e){res.status(500).json({error:e.message});}
});

app.get('/mercado/search',async(req,res)=>{
  const token=req.headers['x-ml-token'];
  if(!token)return res.status(401).json({error:'Token requerido'});
  try{
    const{q,category,sort='relevance',limit=30}=req.query;
    let url=ML+'/sites/MLA/search?limit='+limit+'&sort='+sort;
    if(q)url+='&q='+encodeURIComponent(q);
    if(category)url+='&category='+category;
    const r=await fetch(url,{headers:hdr(token)});
    res.json(await r.json());
  }catch(e){res.status(500).json({error:e.message});}
});

app.get('/mercado/categoria',async(req,res)=>{
  const token=req.headers['x-ml-token'];
  if(!token)return res.status(401).json({error:'Token requerido'});
  const{category,sort='sold_quantity_desc',limit=50}=req.query;
  if(!category)return res.status(400).json({error:'category requerido'});
  try{
    const r=await fetch(`${ML}/sites/MLA/search?category=${category}&sort=${sort}&limit=${limit}`,{headers:hdr(token)});
    const data=await r.json();
    const vendedores={};
    (data.results||[]).forEach(p=>{
      const sid=p.seller?.id,snick=p.seller?.nickname||'—';
      if(!sid)return;
      if(!vendedores[sid])vendedores[sid]={id:sid,nick:snick,ventas:0,fact:0,pubs:0};
      vendedores[sid].ventas+=p.sold_quantity||0;
      vendedores[sid].fact+=(p.price||0)*(p.sold_quantity||0);
      vendedores[sid].pubs++;
    });
    const topV=Object.values(vendedores).sort((a,b)=>b.fact-a.fact).slice(0,20);
    res.json({pubs:data.results||[],total_pubs:data.paging?.total||0,topVendedores:topV});
  }catch(e){res.status(500).json({error:e.message});}
});

