app.get('/mercado/seller',async(req,res)=>{
  const token=req.headers['x-ml-token'];
  if(!token)return res.status(401).json({error:'Token requerido'});
  const{q}=req.query;
  if(!/^\d+$/.test(q))return res.json({error:'Ingresá el User ID numérico del vendedor',seller:{},items:[]});
  try{
    const[sR,iR]=await Promise.all([
      fetch(ML+'/users/'+q,{headers:hdr(token)}),
      fetch(ML+'/sites/MLA/search?seller_id='+q+'&limit=50&sort=sold_quantity_desc',{headers:hdr(token)})
    ]);
    const seller=await sR.json();
    const items=await iR.json();
    res.json({seller,items:items.results||[]});
  }catch(e){res.status(500).json({error:e.message});}
});

